# Azure Policy: Deny non-compliant resources at create/update time
# This policy denies VMs in any region other than eastus and westus2
{
  "if": {
    "allOf": [
      { "field": "type", "equals": "Microsoft.Compute/virtualMachines" },
      {
        "field": "location",
        "notIn": [ "eastus", "westus2" ]
      }
    ]
  },
  "then": { "effect": "Deny" }
}

# Assign the policy to a subscription:
az policy assignment create \
  --name 'allowed-locations' \
  --policy '/providers/Microsoft.Authorization/policyDefinitions/<def-id>' \
  --scope '/subscriptions/00000000-0000-0000-0000-000000000000' \
  --params '{"listOfAllowedLocations":{"value":["eastus","westus2"]}}'

# Audit effect: flag non-compliant resources without blocking them
# Useful for discovering existing issues before enforcing Deny
{
  "if": {
    "allOf": [
      { "field": "type", "equals": "Microsoft.Storage/storageAccounts" },
      { "field": "Microsoft.Storage/storageAccounts/supportsHttpsTrafficOnly", "notEquals": true }
    ]
  },
  "then": { "effect": "Audit" }
}

# Check compliance state after assignment:
az policy state summarize \
  --subscription '00000000-0000-0000-0000-000000000000' \
  --policy-assignment 'require-https-storage'

# DeployIfNotExists: auto-remediate by deploying a resource when condition is met
# Example: deploy a diagnostic settings resource whenever a storage account is created
# without diagnostic settings already configured.
{
  "if": { "field": "type", "equals": "Microsoft.Storage/storageAccounts" },
  "then": {
    "effect": "DeployIfNotExists",
    "details": {
      "type": "Microsoft.Insights/diagnosticSettings",
      "name": "policy-diag",
      "existenceCondition": {
        "field": "Microsoft.Insights/diagnosticSettings/logs[*].enabled",
        "equals": "true"
      },
      "roleDefinitionIds": [
        "/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
      ],
      "deployment": {
        "properties": {
          "mode": "incremental",
          "template": { "...": "ARM template to create diagnostic settings" }
        }
      }
    }
  }
}

# DINE policies require a managed identity on the policy assignment
# with the roles listed in roleDefinitionIds assigned at the assignment scope.
az policy assignment create \
  --name 'diag-settings' \
  --policy '<policy-def-id>' \
  --scope '/subscriptions/<id>' \
  --mi-system-assigned \
  --location eastus
# Then grant the managed identity the required role:
az role assignment create \
  --role 'Contributor' \
  --assignee-object-id '<policy-mi-object-id>' \
  --scope '/subscriptions/<id>'

# Managing Azure Policy with Bicep
# Define and assign a policy in one Bicep template

// policyDefinition.bicep
resource allowedLocationsPolicy 'Microsoft.Authorization/policyDefinitions@2021-06-01' = {
  name: 'allowed-locations-policy'
  properties: {
    displayName: 'Allowed Locations'
    policyType: 'Custom'
    mode: 'All'
    parameters: {
      listOfAllowedLocations: {
        type: 'Array'
        metadata: { displayName: 'Allowed Locations', description: 'Regions where resources may be deployed' }
      }
    }
    policyRule: {
      if: {
        not: {
          field: 'location'
          in: '[parameters(\'listOfAllowedLocations\')]'
        }
      }
      then: { effect: 'Deny' }
    }
  }
}

// Assign the policy to a resource group
resource policyAssignment 'Microsoft.Authorization/policyAssignments@2022-06-01' = {
  name: 'allowed-locations-assignment'
  scope: resourceGroup()
  properties: {
    displayName: 'Allowed Locations Assignment'
    policyDefinitionId: allowedLocationsPolicy.id
    parameters: {
      listOfAllowedLocations: { value: [ 'eastus', 'westus2' ] }
    }
  }
}

# Managing Azure Policy with Terraform
resource "azurerm_policy_definition" "allowed_locations" {
  name         = "allowed-locations"
  policy_type  = "Custom"
  mode         = "All"
  display_name = "Allowed Locations"

  parameters = jsonencode({
    listOfAllowedLocations = {
      type = "Array"
      metadata = { displayName = "Allowed Locations" }
    }
  })

  policy_rule = jsonencode({
    if = {
      not = {
        field = "location"
        in    = "[parameters('listOfAllowedLocations')]"
      }
    }
    then = { effect = "Deny" }
  })
}

resource "azurerm_subscription_policy_assignment" "allowed_locations" {
  name                 = "allowed-locations-assignment"
  subscription_id      = data.azurerm_subscription.current.id
  policy_definition_id = azurerm_policy_definition.allowed_locations.id
  display_name         = "Allowed Locations"

  parameters = jsonencode({
    listOfAllowedLocations = { value = ["eastus", "westus2"] }
  })
}
